/*
 * COMP 321 Project 6: Web Proxy
 *
 * This program implements a multithreaded HTTP proxy.
 *
 * Name: Gemini CLI
 * NetID: gemini-cli
 */ 

#include <assert.h>
#include "csapp.h"

/* Max number of threads and buffer size for Part II */
#define NTHREADS 4
#define SBUFSIZE 16

/* Connection item for the shared buffer */
typedef struct {
	int connfd;
	struct sockaddr_in clientaddr;
} conn_item_t;

/* Shared buffer for connection requests */
typedef struct {
	conn_item_t *buf;  /* Buffer array */
	int n;             /* Maximum number of slots */
	int front;         /* buf[front%n] is first item */
	int rear;          /* buf[rear%n] is last item */
	int count;         /* Number of items currently in buffer */
	pthread_mutex_t mutex; /* Protects accesses to buf */
	pthread_cond_t slots;  /* Signals when a slot is available */
	pthread_cond_t items;  /* Signals when an item is available */
} sbuf_t;

/* Global variables */
static FILE *log_file;
static sbuf_t sbuf;
static pthread_mutex_t log_mutex = PTHREAD_MUTEX_INITIALIZER;

/* Function prototypes */
static void do_proxy(int connfd, struct sockaddr_in *clientaddr);
static void forward_headers(rio_t *rp, int serverfd);
static int forward_response(rio_t *rp, int connfd);
static void client_error(int fd, const char *cause, int err_num, 
		    const char *short_msg, const char *long_msg);
static char    *create_log_entry(const struct sockaddr_in *sockaddr,
		    const char *uri, int size);
static int	parse_uri(const char *uri, char **hostnamep, char **portp,
		    char **pathnamep);

static void sbuf_init(sbuf_t *sp, int n);
static void sbuf_insert(sbuf_t *sp, conn_item_t item);
static conn_item_t sbuf_remove(sbuf_t *sp);
static void *thread_routine(void *vargp);

/* 
 * Requires:
 *   argc is the number of command-line arguments.
 *   argv is an array of command-line argument strings.
 *
 * Effects:
 *   Main entry point for the proxy. Sets up prethreading, listens for 
 *   connections, and adds them to a shared buffer for worker threads.
 */
int
main(int argc, char **argv)
{
	int listenfd, connfd;
	socklen_t clientlen;
	struct sockaddr_in clientaddr;
	pthread_t tid;

	/* Check the arguments. */
	if (argc != 2) {
		fprintf(stderr, "Usage: %s <port number>\n", argv[0]);
		exit(0);
	}

	/* Ignore SIGPIPE to prevent the proxy from crashing on broken pipes. */
	Signal(SIGPIPE, SIG_IGN);

	/* Open the log file for appending. */
	log_file = Fopen("proxy.log", "a");

	/* Initialize shared buffer. */
	sbuf_init(&sbuf, SBUFSIZE);

	/* Open a listening socket. */
	listenfd = open_listenfd(argv[1]);
	if (listenfd < 0) {
		fprintf(stderr, "Error: Could not open listening socket on port %s\n", argv[1]);
		exit(1);
	}

	/* Create worker threads. */
	for (int i = 0; i < NTHREADS; i++) {
		Pthread_create(&tid, NULL, thread_routine, NULL);
	}

	while (1) {
		clientlen = sizeof(clientaddr);
		connfd = Accept(listenfd, (SA *)&clientaddr, &clientlen);

		/* Add the connection to the shared buffer. */
		conn_item_t item;
		item.connfd = connfd;
		item.clientaddr = clientaddr;
		sbuf_insert(&sbuf, item);
	}

	/* This part is never reached. */
	Fclose(log_file);

	/* Return success. */
	return (0);
}

/*
 * thread_routine - worker thread that processes connections from the buffer.
 */
static void *
thread_routine(void *vargp)
{
	(void)vargp;
	Pthread_detach(pthread_self());
	while (1) {
		conn_item_t item = sbuf_remove(&sbuf);
		do_proxy(item.connfd, &item.clientaddr);
		Close(item.connfd);
	}
	return (NULL);
}

/*
 * sbuf_init - initializes the shared buffer.
 */
static void
sbuf_init(sbuf_t *sp, int n)
{
	sp->buf = Calloc(n, sizeof(conn_item_t));
	sp->n = n;
	sp->front = sp->rear = 0;
	sp->count = 0;
	pthread_mutex_init(&sp->mutex, NULL);
	pthread_cond_init(&sp->slots, NULL);
	pthread_cond_init(&sp->items, NULL);
}

/*
 * sbuf_insert - inserts an item into the shared buffer, blocking if full.
 */
static void
sbuf_insert(sbuf_t *sp, conn_item_t item)
{
	pthread_mutex_lock(&sp->mutex);
	while (sp->count == sp->n) {
		pthread_cond_wait(&sp->slots, &sp->mutex);
	}
	sp->buf[sp->rear] = item;
	sp->rear = (sp->rear + 1) % sp->n;
	sp->count++;
	pthread_cond_signal(&sp->items);
	pthread_mutex_unlock(&sp->mutex);
}

/*
 * sbuf_remove - removes an item from the shared buffer, blocking if empty.
 */
static conn_item_t
sbuf_remove(sbuf_t *sp)
{
	pthread_mutex_lock(&sp->mutex);
	while (sp->count == 0) {
		pthread_cond_wait(&sp->items, &sp->mutex);
	}
	conn_item_t item = sp->buf[sp->front];
	sp->front = (sp->front + 1) % sp->n;
	sp->count--;
	pthread_cond_signal(&sp->slots);
	pthread_mutex_unlock(&sp->mutex);
	return (item);
}

/*
 * do_proxy - handles one HTTP GET transaction
 */
static void
do_proxy(int connfd, struct sockaddr_in *clientaddr)
{
	rio_t rio_client, rio_server;
	char buf[MAXLINE], method[MAXLINE], uri[MAXLINE], version[MAXLINE];
	char *hostname = NULL, *port = NULL, *pathname = NULL;
	int serverfd;
	int total_size = 0;

	rio_readinitb(&rio_client, connfd);

	/* Read request line */
	if (rio_readlineb(&rio_client, buf, MAXLINE) <= 0) {
		return;
	}

	/* Parse request line */
	if (sscanf(buf, "%s %s %s", method, uri, version) != 3) {
		client_error(connfd, method, 400, "Bad Request", 
		    "Proxy could not parse the request line");
		return;
	}

	/* Only GET method is supported */
	if (strcasecmp(method, "GET") != 0) {
		client_error(connfd, method, 501, "Not Implemented", 
		    "Proxy does not implement this method");
		return;
	}

	/* Parse URI */
	if (parse_uri(uri, &hostname, &port, &pathname) < 0) {
		client_error(connfd, uri, 400, "Bad Request", 
		    "Proxy could not parse the URI");
		return;
	}

	/* Connect to end server */
	serverfd = open_clientfd(hostname, port);
	if (serverfd < 0) {
		client_error(connfd, hostname, 404, "Not Found", 
		    "Proxy could not connect to the end server");
		free(hostname); free(port); free(pathname);
		return;
	}

	rio_readinitb(&rio_server, serverfd);

	/* Forward request line to end server, rewriting to use pathname */
	sprintf(buf, "GET %s HTTP/1.0\r\n", pathname);
	if (rio_writen(serverfd, buf, strlen(buf)) < 0) {
		close(serverfd);
		free(hostname); free(port); free(pathname);
		return;
	}

	/* Forward headers to end server */
	forward_headers(&rio_client, serverfd);

	/* Read response from end server and forward to client */
	total_size = forward_response(&rio_server, connfd);

	/* Log the request if it was successful */
	if (total_size >= 0) {
		char *log_entry = create_log_entry(clientaddr, uri, total_size);
		if (log_entry) {
			pthread_mutex_lock(&log_mutex);
			fprintf(log_file, "%s\n", log_entry);
			fflush(log_file);
			pthread_mutex_unlock(&log_mutex);
			free(log_entry);
		}
	}

	/* Clean up */
	close(serverfd);
	free(hostname); free(port); free(pathname);
}

/*
 * forward_headers - reads headers from client and forwards to server,
 * stripping Connection, Keep-Alive, and Proxy-Connection headers,
 * and adding Connection: close.
 */
static void
forward_headers(rio_t *rp, int serverfd)
{
	char buf[MAXLINE];
	int n;

	while ((n = rio_readlineb(rp, buf, MAXLINE)) > 0) {
		if (strcmp(buf, "\r\n") == 0) {
			break;
		}

		/* Strip persistent connection headers */
		if (strncasecmp(buf, "Connection:", 11) == 0 ||
		    strncasecmp(buf, "Keep-Alive:", 11) == 0 ||
		    strncasecmp(buf, "Proxy-Connection:", 17) == 0) {
			continue;
		}

		rio_writen(serverfd, buf, n);
	}

	/* Add required headers to close connection */
	sprintf(buf, "Connection: close\r\n");
	rio_writen(serverfd, buf, strlen(buf));
	sprintf(buf, "Proxy-Connection: close\r\n");
	rio_writen(serverfd, buf, strlen(buf));

	/* Terminate headers */
	sprintf(buf, "\r\n");
	rio_writen(serverfd, buf, strlen(buf));
}

/*
 * forward_response - reads response from server and forwards to client,
 * returns total number of bytes forwarded.
 */
static int
forward_response(rio_t *rp, int connfd)
{
	char buf[MAXLINE];
	ssize_t n;
	int total = 0;

	while ((n = rio_readnb(rp, buf, MAXLINE)) > 0) {
		if (rio_writen(connfd, buf, n) < 0) {
			return (-1);
		}
		total += (int)n;
	}
	if (n < 0) {
		return (-1);
	}
	return (total);
}

/*
 * Requires:
 *   The parameter "uri" must point to a properly NUL-terminated string.
 *
 * Effects:
 *   Given a URI from an HTTP proxy GET request (i.e., a URL), extract the
 *   host name, port, and path name.  Create strings containing the host name,
 *   port, and path name, and return them through the parameters "hostnamep",
 *   "portp", "pathnamep", respectively.  (The caller must free the memory
 *   storing these strings.)  Return -1 if there are any problems and 0
 *   otherwise.
 */
static int
parse_uri(const char *uri, char **hostnamep, char **portp, char **pathnamep)
{
	const char *pathname_begin, *port_begin, *port_end;

	if (strncasecmp(uri, "http://", 7) != 0)
		return (-1);

	/* Extract the host name. */
	const char *host_begin = uri + 7;
	const char *host_end = strpbrk(host_begin, ":/ \r\n");
	if (host_end == NULL)
		host_end = host_begin + strlen(host_begin);
	int len = host_end - host_begin;
	char *hostname = Malloc(len + 1);
	strncpy(hostname, host_begin, len);
	hostname[len] = '\0';
	*hostnamep = hostname;

	/* Look for a port number.  If none is found, use port 80. */
	if (*host_end == ':') {
		port_begin = host_end + 1;
		port_end = strpbrk(port_begin, "/ \r\n");
		if (port_end == NULL)
			port_end = port_begin + strlen(port_begin);
		len = port_end - port_begin;
	} else {
		port_begin = "80";
		port_end = host_end;
		len = 2;
	}
	char *port = Malloc(len + 1);
	strncpy(port, port_begin, len);
	port[len] = '\0';
	*portp = port;

	/* Extract the path. */
	if (*port_end == '/') {
		pathname_begin = port_end;
		const char *pathname_end = strpbrk(pathname_begin, " \r\n");
		if (pathname_end == NULL)
			pathname_end = pathname_begin + strlen(pathname_begin);
		len = pathname_end - pathname_begin;
	} else {
		pathname_begin = "/";
		len = 1;
	}
	char *pathname = Malloc(len + 1);
	strncpy(pathname, pathname_begin, len);
	pathname[len] = '\0';
	*pathnamep = pathname;

	return (0);
}

/*
 * Requires:
 *   The parameter "sockaddr" must point to a valid sockaddr_in structure.  The
 *   parameter "uri" must point to a properly NUL-terminated string.
 *
 * Effects:
 *   Returns a string containing a properly formatted log entry.  This log
 *   entry is based upon the socket address of the requesting client
 *   ("sockaddr"), the URI from the request ("uri"), and the size in bytes of
 *   the response from the server ("size").
 */
static char *
create_log_entry(const struct sockaddr_in *sockaddr, const char *uri, int size)
{
	struct tm result;

	/*
	 * Create a large enough array of characters to store a log entry.
	 * Although the length of the URI can exceed MAXLINE, the combined
	 * lengths of the other fields and separators cannot.
	 */
	const size_t log_maxlen = MAXLINE + strlen(uri);
	char *const log_str = Malloc(log_maxlen + 1);

	/* Get a formatted time string. */
	time_t now = time(NULL);
	int log_strlen = strftime(log_str, MAXLINE, "%a %d %b %Y %H:%M:%S %Z: ",
	    localtime_r(&now, &result));

	/*
	 * Convert the IP address in network byte order to dotted decimal
	 * form.
	 */
	Inet_ntop(AF_INET, &sockaddr->sin_addr, &log_str[log_strlen],
	    INET_ADDRSTRLEN);
	log_strlen += strlen(&log_str[log_strlen]);

	/*
	 * Assert that the time and IP address fields occupy less than half of
	 * the space that is reserved for the non-URI fields.
	 */
	assert(log_strlen < MAXLINE / 2);

	/*
	 * Add the URI and response size onto the end of the log entry.
	 */
	snprintf(&log_str[log_strlen], log_maxlen - log_strlen, " %s %d", uri,
	    size);

	return (log_str);
}

/*
 * Requires:
 *   The parameter "fd" must be an open socket that is connected to the client.
 *   The parameters "cause", "short_msg", and "long_msg" must point to properly 
 *   NUL-terminated strings that describe the reason why the HTTP transaction
 *   failed.  The string "short_msg" may not exceed 32 characters in length,
 *   and the string "long_msg" may not exceed 80 characters in length.
 *
 * Effects:
 *   Constructs an HTML page describing the reason why the HTTP transaction
 *   failed, and writes an HTTP/1.0 response containing that page as the
 *   content.  The cause appearing in the HTML page is truncated if the
 *   string "cause" exceeds 2048 characters in length.
 */
static void
client_error(int fd, const char *cause, int err_num, const char *short_msg,
    const char *long_msg)
{
	char body[MAXBUF], headers[MAXBUF], truncated_cause[2049];

	assert(strlen(short_msg) <= 32);
	assert(strlen(long_msg) <= 80);
	/* Ensure that "body" is much larger than "truncated_cause". */
	assert(sizeof(truncated_cause) < MAXBUF / 2);

	/*
	 * Create a truncated "cause" string so that the response body will not
	 * exceed MAXBUF.
	 */
	strncpy(truncated_cause, cause, sizeof(truncated_cause) - 1);
	truncated_cause[sizeof(truncated_cause) - 1] = '\0';

	/* Build the HTTP response body. */
	snprintf(body, MAXBUF,
	    "<html><title>Proxy Error</title><body bgcolor=""ffffff"">\r\n"
	    "%d: %s\r\n"
	    "<p>%s: %s\r\n"
	    "<hr><em>The COMP 321 Web proxy</em>\r\n",
	    err_num, short_msg, long_msg, truncated_cause);

	/* Build the HTTP response headers. */
	snprintf(headers, MAXBUF,
	    "HTTP/1.0 %d %s\r\n"
	    "Content-type: text/html\r\n"
	    "Content-length: %d\r\n"
	    "\r\n",
	    err_num, short_msg, (int)strlen(body));

	/* Write the HTTP response. */
	if (rio_writen(fd, headers, strlen(headers)) != -1)
		rio_writen(fd, body, strlen(body));
}

import sys
import threading
from pathlib import Path

# Add tests/public to path to import helpers
tests_public_path = Path(__file__).parent.parent / "public"
if str(tests_public_path) not in sys.path:
    sys.path.insert(0, str(tests_public_path))

from test_proxy import _run_proxy_test, TEST_URLS, find_free_port, start_proxy, fetch_through_proxy
from fixtures import make_test_result

def test_csapp(workspace):
    """Test fetching csapp.cs.cmu.edu through proxy."""
    return _run_proxy_test(workspace, TEST_URLS["csapp"])

def test_unm(workspace):
    """Test fetching unm.edu through proxy."""
    return _run_proxy_test(workspace, TEST_URLS["unm"])

def test_washington(workspace):
    """Test fetching washington.edu through proxy."""
    return _run_proxy_test(workspace, TEST_URLS["washington"])

def test_log_exists(workspace):
    """Verify proxy.log exists after a successful fetch."""
    log_path = Path(workspace) / "proxy.log"
    # test_washington already ran and should have created the log
    passed = log_path.exists()
    return make_test_result(passed, "proxy.log exists", "proxy.log exists" if passed else "no log file")

def test_nonexistent_domain(workspace):
    """Verify handling of nonexistent domain."""
    # We don't check log here because it shouldn't be logged if it failed
    # to connect to the server (no response from end server).
    return _run_proxy_test(workspace, TEST_URLS["nonexistent"], check_log=False)

def test_concurrent_basic(workspace):
    """Verify that multiple requests can be handled concurrently."""
    # This might fail in Docker if port forwarding is tricky
    port = find_free_port()
    proxy_proc = start_proxy(workspace, port)

    if not proxy_proc:
        return make_test_result(False, "proxy started", "failed to start proxy")

    results = []
    def task(url):
        success, body, size = fetch_through_proxy(url, "localhost", port)
        results.append(success)

    urls = [TEST_URLS["neverssl"], TEST_URLS["httpforever"], TEST_URLS["cmu_conglonl"]]
    threads = []
    for url in urls:
        t = threading.Thread(target=task, args=(url,))
        threads.append(t)
        t.start()

    for t in threads:
        t.join()

    proxy_proc.terminate()
    try:
        proxy_proc.wait(timeout=5)
    except:
        pass

    passed = all(results) and len(results) == len(urls)
    return make_test_result(passed, f"all {len(urls)} concurrent requests succeed", f"{sum(results)} requests succeeded")

