+	pthread_mutex_lock(&sp->mutex);
+	while (sp->count == 0) {
+		pthread_cond_wait(&sp->items, &sp->mutex);
+	}
+	conn_item_t item = sp->buf[sp->front];
+	sp->front = (sp->front + 1) % sp->n;
+	sp->count--;
+	pthread_cond_signal(&sp->slots);
+	pthread_mutex_unlock(&sp->mutex);
+	return (item);
+}
+
+/*
+ * do_proxy - handles one HTTP GET transaction
+ */
+static void
+do_proxy(int connfd, struct sockaddr_in *clientaddr)
+{
+	rio_t rio_client, rio_server;
+	char buf[MAXLINE], method[MAXLINE], uri[MAXLINE], version[MAXLINE];
+	char *hostname = NULL, *port = NULL, *pathname = NULL;
+	int serverfd;
+	int total_size = 0;
+
+	rio_readinitb(&rio_client, connfd);
+
+	/* Read request line */
+	if (rio_readlineb(&rio_client, buf, MAXLINE) <= 0) {
+		return;
+	}
+
+	/* Parse request line */
+	if (sscanf(buf, "%s %s %s", method, uri, version) != 3) {
+		client_error(connfd, method, 400, "Bad Request", 
+		    "Proxy could not parse the request line");
+		return;
+	}
+
+	/* Only GET method is supported */
+	if (strcasecmp(method, "GET") != 0) {
+		client_error(connfd, method, 501, "Not Implemented", 
+		    "Proxy does not implement this method");
+		return;
+	}
+
+	/* Parse URI */
+	if (parse_uri(uri, &hostname, &port, &pathname) < 0) {
+		client_error(connfd, uri, 400, "Bad Request", 
+		    "Proxy could not parse the URI");
+		return;
+	}
+
+	/* Connect to end server */
+	serverfd = open_clientfd(hostname, port);
+	if (serverfd < 0) {
+		client_error(connfd, hostname, 404, "Not Found", 
+		    "Proxy could not connect to the end server");
+		free(hostname); free(port); free(pathname);
+		return;
+	}
+
+	rio_readinitb(&rio_server, serverfd);
+
+	/* Forward request line to end server, rewriting to use pathname */
+	sprintf(buf, "GET %s HTTP/1.0\r\n", pathname);
+	if (rio_writen(serverfd, buf, strlen(buf)) < 0) {
+		close(serverfd);
+		free(hostname); free(port); free(pathname);
+		return;
+	}
+
+	/* Forward headers to end server */
+	forward_headers(&rio_client, serverfd);
+
+	/* Read response from end server and forward to client */
+	total_size = forward_response(&rio_server, connfd);
+
+	/* Log the request if it was successful */
+	if (total_size >= 0) {
+		char *log_entry = create_log_entry(clientaddr, uri, total_size);
+		if (log_entry) {
+			pthread_mutex_lock(&log_mutex);
+			fprintf(log_file, "%s\n", log_entry);
+			fflush(log_file);
+			pthread_mutex_unlock(&log_mutex);
+			free(log_entry);
+		}
+	}
+
+	/* Clean up */
+	close(serverfd);
+	free(hostname); free(port); free(pathname);
+}
+
+/*
+ * forward_headers - reads headers from client and forwards to server,
+ * stripping Connection, Keep-Alive, and Proxy-Connection headers,
+ * and adding Connection: close.
+ */
+static void
+forward_headers(rio_t *rp, int serverfd)
+{
+	char buf[MAXLINE];
+	int n;
+
+	while ((n = rio_readlineb(rp, buf, MAXLINE)) > 0) {
+		if (strcmp(buf, "\r\n") == 0) {
+			break;
+		}
+
+		/* Strip persistent connection headers */
+		if (strncasecmp(buf, "Connection:", 11) == 0 ||
+		    strncasecmp(buf, "Keep-Alive:", 11) == 0 ||
+		    strncasecmp(buf, "Proxy-Connection:", 17) == 0) {
+			continue;
+		}
+
+		rio_writen(serverfd, buf, n);
+	}
+
+	/* Add required headers to close connection */
+	sprintf(buf, "Connection: close\r\n");
+	rio_writen(serverfd, buf, strlen(buf));
+	sprintf(buf, "Proxy-Connection: close\r\n");
+	rio_writen(serverfd, buf, strlen(buf));
+
+	/* Terminate headers */
+	sprintf(buf, "\r\n");
+	rio_writen(serverfd, buf, strlen(buf));
+}
+
+/*
+ * forward_response - reads response from server and forwards to client,
+ * returns total number of bytes forwarded.
+ */
+static int
+forward_response(rio_t *rp, int connfd)
+{
+	char buf[MAXLINE];
+	ssize_t n;
+	int total = 0;
+
+	while ((n = rio_readnb(rp, buf, MAXLINE)) > 0) {
+		if (rio_writen(connfd, buf, n) < 0) {
+			return (-1);
+		}
+		total += (int)n;
+	}
+	if (n < 0) {
+		return (-1);
+	}
+	return (total);
+}
